EXPLAIN OPTIMIZED PLAN WITH(humanized expressions, arity, join implementations) AS VERBOSE TEXT FOR
WITH seeds AS (
            SELECT
                regexp_split_to_table(
                    regexp_split_to_array(
                        regexp_split_to_array(input, '\n')[1],
                        ': '
                    )[2],
                    ' '
                )::bigint AS seed
